INSERT INTO `properties` (`id`, `host_id`, `name`, `type`, `location`, `price_display`, `description`, `map_image`, `map_embed`, `is_hot`, `created_at`) VALUES
(1, 1, 'Khách sạn Sân bay Havana', 'hotel', 'TP. Hồ Chí Minh, Việt Nam', '2500000', 'Khách sạn này là sự lựa chọn hoàn hảo cho các cặp đôi đang tìm kiếm một kỳ nghỉ lãng mạn hoặc một nơi nghỉ trăng mật. Tận hưởng những đêm đáng nhớ nhất với người yêu của bạn bằng cách ở tại Havana Airport Hotel.\n\nHavana Airport Hotel là một khách sạn gần Sân bay, một nơi ở lý tưởng trong khi chờ chuyến bay tiếp theo của bạn. Tận hưởng một nơi nghỉ ngơi thoải mái trong quá trình di chuyển của bạn.\n\nTừ sự kiện kinh doanh đến các cuộc họp công ty, Havana Airport Hotel cung cấp các dịch vụ và tiện nghi hoàn chỉnh mà bạn và đồng nghiệp của bạn cần.\n\nHãy vui vẻ với nhiều tiện nghi giải trí khác nhau dành cho bạn và cả gia đình tại Havana Airport Hotel, một nơi ở tuyệt vời cho kỳ nghỉ gia đình của bạn.\n\nNếu bạn dự định có một kỳ nghỉ dài hạn, việc ở tại Havana Airport Hotel là sự lựa chọn phù hợp với bạn. Cung cấp nhiều loại tiện nghi và chất lượng dịch vụ tuyệt vời, chỗ ở này chắc chắn sẽ khiến bạn cảm thấy như ở nhà.\n\nTrong khi đi du lịch với bạn bè có thể rất vui, thì việc đi du lịch một mình lại có những đặc quyền riêng. Đối với chỗ ở, Havana Airport Hotel phù hợp với những người coi trọng sự riêng tư trong thời gian lưu trú.\n\nDịch vụ tuyệt vời cùng với nhiều tiện nghi được cung cấp sẽ khiến bạn không phàn nàn trong thời gian lưu trú tại Havana Airport Hotel.\n\nWi-Fi có sẵn trong các khu vực công cộng của khách sạn để giúp bạn giữ liên lạc với gia đình và bạn bè.\n\nVới tất cả các tiện nghi được cung cấp, Havana Airport Hotel là nơi thích hợp để ở.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuDrvgMY2AVYnyzdxJ39yFL_WbpvtD1wm0CaNoF8o7h3Il4noOJCeeVcPI7wi5PRMfL1btdG8pqW25RGjR-SonElWR2VukmexroNqQagpynpDmh6PqZEfU9CD1Qaav3NM3O0xgXzec-bjdBA5VR9A523HSotNrPoV3f6tPvChAYEHYQn_da2dQJjOs8d-GLGh5vh9vIiVmivt', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3919.003571913024!2d106.66654419999999!3d10.8110377!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x317529e0d1745e63%3A0x4fd96c21d1427f08!2sHavana%20Airport%20Hotel!5e0!3m2!1svi!2s!4v1764412109071!5m2!1svi!2s', 0, '2026-03-08 18:49:23'),
(31, 1, 'Khách sạn Muong Thanh Holiday Mui Ne', 'hotel', 'Mũi Né, TP. Phan Thiết, Bình Thuận', '1100000', 'Khách sạn này là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn hay tuần trăng mật của các cặp đôi. Quý khách hãy tận hưởng những đêm đáng nhớ nhất cùng người thương của mình tại Muong Thanh Holiday Mui Ne Hotel.\n\nMuong Thanh Holiday Mui Ne Hotel là lựa chọn sáng giá dành cho những ai đang tìm kiếm một trải nghiệm xa hoa đầy thú vị trong kỳ nghỉ của mình. Lưu trú tại đây cũng là cách để quý khách chiều chuộng bản thân với những dịch vụ xuất sắc nhất và khiến kỳ nghỉ của mình trở nên thật đáng nhớ.\n\nTừ sự kiện doanh nghiệp đến họp mặt công ty, Muong Thanh Holiday Mui Ne Hotel cung cấp đầy đủ các dịch vụ và tiện nghi đáp ứng mọi nhu cầu của quý khách và đồng nghiệp.\n\nHãy tận hưởng thời gian vui vẻ cùng cả gia đình với hàng loạt tiện nghi giải trí tại Muong Thanh Holiday Mui Ne Hotel, một khách sạn tuyệt vời phù hợp cho mọi kỳ nghỉ bên người thân.\n\nHãy sẵn sàng đón nhận trải nghiệm khó quên bằng dịch vụ độc đáo và hoàn hảo của khách sạn cùng các tiện nghi đầy đủ, đáp ứng mọi nhu cầu của quý khách.\n\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\n\nTận hưởng những món ăn yêu thích với phong cách ẩm thực đặc biệt từ Muong Thanh Holiday Mui Ne Hotel chỉ dành riêng cho quý khách.\n\nSóng WiFi phủ khắp các khu vực chung của khách sạn cho phép quý khách luôn kết nối với gia đình và bè bạn.\n\nMuong Thanh Holiday Mui Ne Hotel là khách sạn sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\n\nHãy sẵn sàng đón nhận những giây phút vô giá khó phai trong suốt kỳ nghỉ của quý khách tại Muong Thanh Holiday Mui Ne Hotel.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuDS0KIlSsN6dJIYuXVnex_-8DaJKtQBg5UAQea5dbOBBa_Evp7fTc60n9s4dWfX2y_rPXywBCnDE5JjwjgqSQ8cx1TkzipPkffG59yVVhzSDhLyp3Ka0RoZ0Ch-ILdXuF11r77qjlKXTjqho0CQgG18oqDWFdYWjLFDF1yFR3tVSBFzKuObXkOCKf6pCPEpNHSf18Ao4CZPu', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d177337.39921157522!2d108.31133615161234!3d10.838843507692536!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x31768fe64bcdc76f%3A0x75da7e615cb2bb6f!2sM%C6%B0%E1%BB%9Dng%20Thanh%20Holiday%20Mui%20Ne%20Hotel!5e0!3m2!1svi!2s!4v1764508208910!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(32, 1, 'The Anam Mui Ne', 'hotel', 'Phường Mũi Né, TP. Phan Thiết, Bình Thuận', '4500000', 'Từ sự kiện doanh nghiệp đến họp mặt công ty, The Anam Mui Ne cung cấp đầy đủ các dịch vụ và tiện nghi đáp ứng mọi nhu cầu của quý khách và đồng nghiệp.\nKhách sạn này là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn hay tuần trăng mật của các cặp đôi. Quý khách hãy tận hưởng những đêm đáng nhớ nhất cùng người thương của mình tại The Anam Mui Ne\nNếu dự định có một kỳ nghỉ dài, thì The Anam Mui Ne chính là lựa chọn dành cho quý khách. Với đầy đủ tiện nghi với chất lượng dịch vụ tuyệt vời, The Anam Mui Ne sẽ khiến quý khách cảm thấy thoải mái như đang ở nhà vậy.\nThe Anam Mui Ne là lựa chọn sáng giá dành cho những ai đang tìm kiếm một trải nghiệm xa hoa đầy thú vị trong kỳ nghỉ của mình. Lưu trú tại đây cũng là cách để quý khách chiều chuộng bản thân với những dịch vụ xuất sắc nhất và khiến kỳ nghỉ của mình trở nên thật đáng nhớ.\nKhách sạn này là nơi tốt nhất dành cho những ai mong muốn một nơi thanh bình, thư thái để ẩn mình khỏi đám đông ồn ã, xô bồ.\nDịch vụ thượng hạng song hành với hàng loạt tiện nghi phong phú sẽ đem đến cho quý khách trải nghiệm của một kỳ nghỉ viên mãn nhất.\nTrung tâm thể dục của nơi nghỉ là một trong những tiện nghi không thể bỏ qua khi lưu trú tại đây.\nNhận ưu đãi đặc biệt dành cho các liệu pháp spa tinh tuý nhất giúp thư giãn tinh thần và làm tươi trẻ cơ thể.\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\nTận hưởng những món ăn yêu thích với phong cách ẩm thực đặc biệt từ The Anam Mui Ne chỉ dành riêng cho quý khách.\nSóng WiFi phủ khắp các khu vực chung của nơi nghỉ cho phép quý khách luôn kết nối với gia đình và bè bạn.\nThe Anam Mui Ne là nơi nghỉ sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\nHãy sẵn sàng đón nhận những giây phút vô giá khó phai trong suốt kỳ nghỉ của quý khách tại The Anam Mui Ne.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuAvC4g-ucPNpf1l1ZYbPyNYJ9bhFTjfbxuOn5OQGuA4TwMBoFukthwEr5pPwtlExWEkXViZgAuXBYKS7bOnGJHjmur5VGjPPnrwYYeLU8Tlf2gAh0_MkDZnmwYd6XuPJWA3Nx5Tg7VA-1-afX3wWDgfaTI9tjOUg0XD44bZZZTzmfhOmlAceUVKMmaEuKf53Ycrrgxer8e_2', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3917.266061967311!2d108.1943945!3d10.943263499999999!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x31768560fadd3569%3A0x377cd94d4e5dcf23!2sThe%20Anam%20Mui%20Ne!5e0!3m2!1svi!2s!4v1764509888380!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(33, 1, 'Amana Hotel Phan Thiet', 'hotel', 'Phường Phú Thủy, TP. Phan Thiết, Bình Thuận', '650000', 'Dịch vụ tuyệt vời, cơ sở vật chất hoàn chỉnh và các tiện nghi khách sạn cung cấp sẽ khiến quý khách không thể phàn nàn trong suốt kỳ lưu trú tại Amana Hotel Phan Thiet.\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\nSóng WiFi phủ khắp các khu vực chung của khách sạn cho phép quý khách luôn kết nối với gia đình và bè bạn.\nAmana Hotel Phan Thiet là khách sạn sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\nVới những tiện nghi sẵn có Amana Hotel Phan Thiet thực sự là một nơi lưu trú hoàn hảo.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuAvC4g-ucPNpf1l1ZYbPyNYJ9bhFTjfbxuOn5OQGuA4TwMBoFukthwEr5pPwtlExWEkXViZgAuXBYKS7bOnGJHjmur5VGjPPnrwYYeLU8Tlf2gAh0_MkDZnmwYd6XuPJWA3Nx5Tg7VA-1-afX3wWDgfaTI9tjOUg0XD44bZZZTzmfhOmlAceUVKMmaEuKf53Ycrrgxer8e_2', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3917.4442669558703!2d108.11885679999999!3d10.9297747!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x317683e2e7d63a85%3A0x7f8bd20c2114d6b7!2sAMANA%20Hotel%20Phan%20Thiet!5e0!3m2!1svi!2s!4v1764511587374!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(34, 1, 'Le\' VIVA Resort Mui Ne', 'hotel', 'TP. Phan Thiết, Bình Thuận', '1150000', 'Dù quý khách muốn tổ chức một sự kiện hay các dịp kỷ niệm đặc biệt khác, Le\' VIVA Resort Mui Ne là lựa chọn tuyệt vời cho quý khách với phòng chức năng rộng lớn, được trang bị đầy đủ để sẵn sàng đáp ứng mọi yêu cầu.\nKhách sạn này là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn hay tuần trăng mật của các cặp đôi. Quý khách hãy tận hưởng những đêm đáng nhớ nhất cùng người thương của mình tại Le\' VIVA Resort Mui Ne\nLe\' VIVA Resort Mui Ne là lựa chọn sáng giá dành cho những ai đang tìm kiếm một trải nghiệm xa hoa đầy thú vị trong kỳ nghỉ của mình. Lưu trú tại đây cũng là cách để quý khách chiều chuộng bản thân với những dịch vụ xuất sắc nhất và khiến kỳ nghỉ của mình trở nên thật đáng nhớ.\nMột trong những đặc điểm chính của khách sạn này là các liệu pháp spa đa dạng. Hãy nâng niu bản thân bằng các liệu pháp thư giãn, phục hồi giúp quý khách tươi trẻ thân, tâm.\nTừ sự kiện doanh nghiệp đến họp mặt công ty, Le\' VIVA Resort Mui Ne cung cấp đầy đủ các dịch vụ và tiện nghi đáp ứng mọi nhu cầu của quý khách và đồng nghiệp.\nHãy tận hưởng thời gian vui vẻ cùng cả gia đình với hàng loạt tiện nghi giải trí tại Le\' VIVA Resort Mui Ne, một nơi nghỉ tuyệt vời phù hợp cho mọi kỳ nghỉ bên người thân.\nNếu dự định có một kỳ nghỉ dài, thì Le\' VIVA Resort Mui Ne chính là lựa chọn dành cho quý khách. Với đầy đủ tiện nghi với chất lượng dịch vụ tuyệt vời, Le\' VIVA Resort Mui Ne sẽ khiến quý khách cảm thấy thoải mái như đang ở nhà vậy.\nDu lịch một mình cũng không hề kém phần thú vị và Le\' VIVA Resort Mui Ne là nơi thích hợp dành riêng cho những ai đề cao sự riêng tư trong kỳ lưu trú.\nKhách sạn này là nơi tốt nhất dành cho những ai mong muốn một nơi thanh bình, thư thái để ẩn mình khỏi đám đông ồn ã, xô bồ.\nHãy sẵn sàng đón nhận trải nghiệm khó quên bằng dịch vụ độc đáo và hoàn hảo của nơi nghỉ cùng các tiện nghi đầy đủ, đáp ứng mọi nhu cầu của quý khách.\nTrung tâm thể dục của nơi nghỉ là một trong những tiện nghi không thể bỏ qua khi lưu trú tại đây.\nHưởng thụ một ngày thư thái đầy thú vị tại hồ bơi dù quý khách đang du lịch một mình hay cùng người thân.\nNhận ưu đãi đặc biệt dành cho các liệu pháp spa tinh tuý nhất giúp thư giãn tinh thần và làm tươi trẻ cơ thể.\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\nTận hưởng những món ăn yêu thích với phong cách ẩm thực đặc biệt từ Le\' VIVA Resort Mui Ne chỉ dành riêng cho quý khách.\nSóng WiFi phủ khắp các khu vực chung của nơi nghỉ cho phép quý khách luôn kết nối với gia đình và bè bạn.\nLe\' VIVA Resort Mui Ne là nơi nghỉ sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\nHãy sẵn sàng đón nhận những giây phút vô giá khó phai trong suốt kỳ nghỉ của quý khách tại Le\' VIVA Resort Mui Ne.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuAvC4g-ucPNpf1l1ZYbPyNYJ9bhFTjfbxuOn5OQGuA4TwMBoFukthwEr5pPwtlExWEkXViZgAuXBYKS7bOnGJHjmur5VGjPPnrwYYeLU8Tlf2gAh0_MkDZnmwYd6XuPJWA3Nx5Tg7VA-1-afX3wWDgfaTI9tjOUg0XD44bZZZTzmfhOmlAceUVKMmaEuKf53Ycrrgxer8e_2', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3917.157915314395!2d108.2545907!3d10.951441400000002!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x31768f1c7bcc76a1%3A0xc5869e2b9375e30a!2sLe%20VIVA%20Resort%20Mui%20Ne!5e0!3m2!1svi!2s!4v1764512328577!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(35, 1, 'Biệt thự MyGarden Phan Thiết Beachfront', 'villa', 'Xã Tiến Thành, TP. Phan Thiết, Bình Thuận', '7650000', 'Có một ngày vui vẻ và thư giãn tại hồ bơi, cho dù bạn đi du lịch một mình hay với những người thân yêu của mình.\nQuầy lễ tân 24 giờ luôn sẵn sàng phục vụ bạn, từ nhận phòng đến trả phòng hoặc bất kỳ sự hỗ trợ nào bạn cần. Nếu bạn muốn biết thêm, đừng ngần ngại hỏi quầy lễ tân, chúng tôi luôn sẵn sàng phục vụ bạn.\nNghỉ tại MyGarden Villa Phan Thiet Beachfront chắc chắn sẽ làm bạn hài lòng với sự hiếu khách tuyệt vời và giá cả phải chăng.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuAvC4g-ucPNpf1l1ZYbPyNYJ9bhFTjfbxuOn5OQGuA4TwMBoFukthwEr5pPwtlExWEkXViZgAuXBYKS7bOnGJHjmur5VGjPPnrwYYeLU8Tlf2gAh0_MkDZnmwYd6XuPJWA3Nx5Tg7VA-1-afX3wWDgfaTI9tjOUg0XD44bZZZTzmfhOmlAceUVKMmaEuKf53Ycrrgxer8e_2', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3919.0608236353105!2d108.02905899999999!3d10.806653599999999!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x31742b85766c8ea5%3A0xbbcd964f72420aef!2sMyGarden%20Villa%20Phan%20Thiet%20Beachfront!5e0!3m2!1svi!2s!4v1764513059788!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(41, 1, 'Ylang Garden Villa', 'villa', 'TP. Hội An, Quảng Nam', '8850000', 'Dịch vụ tuyệt vời, cơ sở vật chất hoàn chỉnh và các tiện nghi khách sạn cung cấp sẽ khiến quý khách không thể phàn nàn trong suốt kỳ lưu trú tại Ylang Garden Villa.\nHưởng thụ một ngày thư thái đầy thú vị tại hồ bơi dù quý khách đang du lịch một mình hay cùng người thân.\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\nYlang Garden Villa là khách sạn sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\nVới những tiện nghi sẵn có Ylang Garden Villa thực sự là một nơi lưu trú hoàn hảo.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuAvC4g-ucPNpf1l1ZYbPyNYJ9bhFTjfbxuOn5OQGuA4TwMBoFukthwEr5pPwtlExWEkXViZgAuXBYKS7bOnGJHjmur5VGjPPnrwYYeLU8Tlf2gAh0_MkDZnmwYd6XuPJWA3Nx5Tg7VA-1-afX3wWDgfaTI9tjOUg0XD44bZZZTzmfhOmlAceUVKMmaEuKf53Ycrrgxer8e_2', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3837.494300516853!2d108.35251520000001!3d15.883154299999998!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x31420dc882573fe1%3A0x8c4436fcc55f339a!2sYlang%20Garden%20Villa!5e0!3m2!1svi!2s!4v1764513759793!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(42, 1, 'Hotel Royal Hoi An - Gallery', 'hotel', 'TP. Hội An, Quảng Nam', '2000000', 'Khi lưu trú tại khách sạn thì nội thất và kiến trúc hẳn là hai yếu tố quan trọng khiến quý khách mãn nhãn. Với thiết kế độc đáo, Hotel Royal Hoi An - Gallery mang đến không gian lưu trú làm hài lòng quý khách.\nTừ sự kiện doanh nghiệp đến họp mặt công ty, Hotel Royal Hoi An - Gallery cung cấp đầy đủ các dịch vụ và tiện nghi đáp ứng mọi nhu cầu của quý khách và đồng nghiệp.\nDù quý khách muốn tổ chức một sự kiện hay các dịp kỷ niệm đặc biệt khác, Hotel Royal Hoi An - Gallery là lựa chọn tuyệt vời cho quý khách với phòng chức năng rộng lớn, được trang bị đầy đủ để sẵn sàng đáp ứng mọi yêu cầu.\nHãy tận hưởng thời gian vui vẻ cùng cả gia đình với hàng loạt tiện nghi giải trí tại Hotel Royal Hoi An - Gallery, một khách sạn tuyệt vời phù hợp cho mọi kỳ nghỉ bên người thân.\nHãy tận hưởng trải nghiệm lưu trú có một không hai tại toà nhà mang đậm dấu ấn lịch sử của Hotel Royal Hoi An - Gallery, điều quý khách khó có thể tìm thấy tại bất kỳ đâu.\nKhách sạn này là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn hay tuần trăng mật của các cặp đôi. Quý khách hãy tận hưởng những đêm đáng nhớ nhất cùng người thương của mình tại Hotel Royal Hoi An - Gallery\nNếu dự định có một kỳ nghỉ dài, thì Hotel Royal Hoi An - Gallery chính là lựa chọn dành cho quý khách. Với đầy đủ tiện nghi với chất lượng dịch vụ tuyệt vời, Hotel Royal Hoi An - Gallery sẽ khiến quý khách cảm thấy thoải mái như đang ở nhà vậy.\nHotel Royal Hoi An - Gallery là lựa chọn sáng giá dành cho những ai đang tìm kiếm một trải nghiệm xa hoa đầy thú vị trong kỳ nghỉ của mình. Lưu trú tại đây cũng là cách để quý khách chiều chuộng bản thân với những dịch vụ xuất sắc nhất và khiến kỳ nghỉ của mình trở nên thật đáng nhớ.\nMột trong những đặc điểm chính của khách sạn này là các liệu pháp spa đa dạng. Hãy nâng niu bản thân bằng các liệu pháp thư giãn, phục hồi giúp quý khách tươi trẻ thân, tâm.\nDịch vụ thượng hạng song hành với hàng loạt tiện nghi phong phú sẽ đem đến cho quý khách trải nghiệm của một kỳ nghỉ viên mãn nhất.\nTrung tâm thể dục của khách sạn là một trong những tiện nghi không thể bỏ qua khi lưu trú tại đây.\nNhận ưu đãi đặc biệt dành cho các liệu pháp spa tinh tuý nhất giúp thư giãn tinh thần và làm tươi trẻ cơ thể.\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\nTận hưởng những món ăn yêu thích với phong cách ẩm thực đặc biệt từ Hotel Royal Hoi An - Gallery chỉ dành riêng cho quý khách.\nSóng WiFi phủ khắp các khu vực chung của khách sạn cho phép quý khách luôn kết nối với gia đình và bè bạn.\nHotel Royal Hoi An - Gallery là khách sạn sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\nTận hưởng trải nghiệm lưu trú xa hoa đầy thú vị không đâu sánh bằng tại Hotel Royal Hoi An - Gallery.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuAvC4g-ucPNpf1l1ZYbPyNYJ9bhFTjfbxuOn5OQGuA4TwMBoFukthwEr5pPwtlExWEkXViZgAuXBYKS7bOnGJHjmur5VGjPPnrwYYeLU8Tlf2gAh0_MkDZnmwYd6XuPJWA3Nx5Tg7VA-1-afX3wWDgfaTI9tjOUg0XD44bZZZTzmfhOmlAceUVKMmaEuKf53Ycrrgxer8e_2', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3837.617826285548!2d108.3198424!3d15.8766713!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x31420e62d212ad4b%3A0x1971389a5808ddb6!2sHotel%20Royal%20Hoi%20An%20Gallery!5e0!3m2!1svi!2s!4v1764514447158!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(43, 1, 'Reu Boutique Hotel', 'hotel', 'TP. Hội An, Quảng Nam', '1500000', 'Không chỉ sở hữu vị trí giúp quý khách dễ dàng ghé thăm những địa điểm lý thú trong chuyến hành trình, Reu Boutique Hotel cũng sẽ mang đến cho quý khách trải nghiệm lưu trú mỹ mãn.\nReu Boutique Hotel là đề xuất hàng đầu dành cho những tín đồ du lịch "bụi" mong muốn được nghỉ tại một khách sạn vừa thoải mái lại hợp túi tiền.\nKhi lưu trú tại khách sạn thì nội thất và kiến trúc hẳn là hai yếu tố quan trọng khiến quý khách mãn nhãn. Với thiết kế độc đáo, Reu Boutique Hotel mang đến không gian lưu trú làm hài lòng quý khách.\nTừ sự kiện doanh nghiệp đến họp mặt công ty, Reu Boutique Hotel cung cấp đầy đủ các dịch vụ và tiện nghi đáp ứng mọi nhu cầu của quý khách và đồng nghiệp.\nHãy tận hưởng thời gian vui vẻ cùng cả gia đình với hàng loạt tiện nghi giải trí tại Reu Boutique Hotel, một khách sạn tuyệt vời phù hợp cho mọi kỳ nghỉ bên người thân.\nKhách sạn này là lựa chọn lý tưởng cho cả du khách chơi golf nghiệp dư lẫn chuyên nghiệp.\nHãy tận hưởng trải nghiệm lưu trú có một không hai tại toà nhà mang đậm dấu ấn lịch sử của Reu Boutique Hotel, điều quý khách khó có thể tìm thấy tại bất kỳ đâu.\nKhách sạn này là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn hay tuần trăng mật của các cặp đôi. Quý khách hãy tận hưởng những đêm đáng nhớ nhất cùng người thương của mình tại Reu Boutique Hotel\nNếu dự định có một kỳ nghỉ dài, thì Reu Boutique Hotel chính là lựa chọn dành cho quý khách. Với đầy đủ tiện nghi với chất lượng dịch vụ tuyệt vời, Reu Boutique Hotel sẽ khiến quý khách cảm thấy thoải mái như đang ở nhà vậy.\nReu Boutique Hotel là lựa chọn sáng giá dành cho những ai đang tìm kiếm một trải nghiệm xa hoa đầy thú vị trong kỳ nghỉ của mình. Lưu trú tại đây cũng là cách để quý khách chiều chuộng bản thân với những dịch vụ xuất sắc nhất và khiến kỳ nghỉ của mình trở nên thật đáng nhớ.\nDu lịch một mình cũng không hề kém phần thú vị và Reu Boutique Hotel là nơi thích hợp dành riêng cho những ai đề cao sự riêng tư trong kỳ lưu trú.\nMột trong những đặc điểm chính của khách sạn này là các liệu pháp spa đa dạng. Hãy nâng niu bản thân bằng các liệu pháp thư giãn, phục hồi giúp quý khách tươi trẻ thân, tâm.\nHãy sẵn sàng đón nhận trải nghiệm khó quên bằng dịch vụ độc đáo và hoàn hảo của khách sạn cùng các tiện nghi đầy đủ, đáp ứng mọi nhu cầu của quý khách.\nTrung tâm thể dục của khách sạn là một trong những tiện nghi không thể bỏ qua khi lưu trú tại đây.\nHưởng thụ một ngày thư thái đầy thú vị tại hồ bơi dù quý khách đang du lịch một mình hay cùng người thân.\nNhận ưu đãi đặc biệt dành cho các liệu pháp spa tinh tuý nhất giúp thư giãn tinh thần và làm tươi trẻ cơ thể.\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\nTận hưởng những món ăn yêu thích với phong cách ẩm thực đặc biệt từ Reu Boutique Hotel chỉ dành riêng cho quý khách.\nSóng WiFi phủ khắp các khu vực chung của khách sạn cho phép quý khách luôn kết nối với gia đình và bè bạn.\nReu Boutique Hotel là khách sạn sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\nHãy sẵn sàng đón nhận những giây phút vô giá khó phai trong suốt kỳ nghỉ của quý khách tại Reu Boutique Hotel.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuAvC4g-ucPNpf1l1ZYbPyNYJ9bhFTjfbxuOn5OQGuA4TwMBoFukthwEr5pPwtlExWEkXViZgAuXBYKS7bOnGJHjmur5VGjPPnrwYYeLU8Tlf2gAh0_MkDZnmwYd6XuPJWA3Nx5Tg7VA-1-afX3wWDgfaTI9tjOUg0XD44bZZZTzmfhOmlAceUVKMmaEuKf53Ycrrgxer8e_2', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3837.4081902222565!2d108.3354004!3d15.887672100000001!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x31420d00150fb86d%3A0x2a7b388c71f99f9c!2sR%C3%AAu%20H%E1%BB%99i%20An%20Boutique%20Hotel!5e0!3m2!1svi!2s!4v1764514865951!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(51, 2, 'Elegant Hue Hotel', 'hotel', 'Huế, Việt Nam', '0', 'Elegant Hue Hotel là lựa chọn tuyệt vời dành cho du khách muốn trải nghiệm một kỳ nghỉ thoải mái ngay trung tâm cố đô Huế. Với phong cách thiết kế trang nhã, tiện nghi đầy đủ và đội ngũ nhân viên thân thiện, khách sạn đảm bảo mang đến cho quý khách cảm giác dễ chịu như đang ở chính ngôi nhà của mình.\n\nTại Elegant Hue Hotel, quý khách có thể tận hưởng nhiều tiện ích như nhà hàng, quầy bar, tiệm cà phê và dịch vụ dọn phòng chuyên nghiệp. Khách sạn rất phù hợp cho các chuyến du lịch cùng gia đình, bạn bè hoặc nghỉ dưỡng cá nhân.\n\nVới vị trí thuận tiện gần các điểm tham quan nổi tiếng của thành phố Huế, đây là địa điểm lý tưởng để khám phá văn hóa và lịch sử nơi đây.\n\nElegant Hue Hotel luôn nỗ lực mang đến trải nghiệm lưu trú thoải mái, chu đáo và đáng nhớ cho mọi du khách.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuCbDd5vtbsKwJGeyNSm7Sm9j2C87ZmCv3K7nZN9x7grZ92SEyjJayM0DqBo6ijsH5APv74UOzhbPrp5p9h3f3hHuibjI8Sw7MGt3AFz_i0w2C2EnOyePYf-OJ8ZA1L6EWtCQc1KZrwPUAesUgxgHINnM-wqMBKKI2ICARLxqPy_zuQYe9vIijtntVH6EsHmWc25wfxYwg1WY', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d30609.527456118005!2d107.5561338743164!3d16.465867!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3141a1ae6f9a5513%3A0x5874651d64409fa4!2sElegant%20Hue%20Hotel!5e0!3m2!1svi!2s!4v1764573866803!5m2!1svi!2s', 0, '2026-03-08 18:49:23'),
(52, 3, 'Kobi Onsen Resort Hue, Affiliated by Melia', 'hotel', 'Huế', '1300000', 'Kawara My An Onsen Resort – một khu phức hợp nghỉ dưỡng sức khỏe theo tiêu chuẩn onsen truyền thống của Nhật Bản, một trong những dự án tiêu biểu của BBGroup tại miền Trung Việt Nam.\n\nVới sứ mệnh là người tiên phong trong việc tạo ra các biểu tượng, BB Group đến với Huế với mong muốn chân thành để phát triển và tạo ra những ấn tượng du lịch mới lạ cho cố đô này. Nhờ sự chuyển giao công nghệ và kinh nghiệm vận hành từ Kawara Resort - một trong những thương hiệu khu nghỉ dưỡng suối nước nóng truyền thống nổi tiếng tại Nhật Bản, chúng tôi hy vọng sẽ mang đến cho du khách trải nghiệm về một khu phức hợp nghỉ dưỡng cao cấp, đặc biệt là dịch vụ onsen theo tiêu chuẩn Nhật Bản đáng chú ý và trên hết là sự giao lưu văn hóa giữa Đất nước Mặt trời mọc và Kinh thành Huế.\n\nTọa lạc cách Chợ No khoảng 2km và Chợ Đông Ba 8 km, resort còn cách Cầu Tràng Tiền 7 km. Khách có thể thưởng thức đồ uống tại quầy bar hoặc dùng bữa tại nhà hàng.\n\nBữa sáng tự chọn có thể được thưởng thức tại chỗ nghỉ.\n\nKhách có thể sử dụng trung tâm thể dục.\n\nNhân viên tại quầy lễ tân có thể giúp đỡ suốt ngày đêm với những lời khuyên về khu vực.\n\nHồ Tịnh Tâm cách resort 11 km, trong khi Bảo tàng Cổ vật Hoàng gia cách đó 11 km. Sân bay gần nhất là Sân bay Phú Bài, cách resort 25 km.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuCbDd5vtbsKwJGeyNSm7Sm9j2C87ZmCv3K7nZN9x7grZ92SEyjJayM0DqBo6ijsH5APv74UOzhbPrp5p9h3f3hHuibjI8Sw7MGt3AFz_i0w2C2EnOyePYf-OJ8ZA1L6EWtCQc1KZrwPUAesUgxgHINnM-wqMBKKI2ICARLxqPy_zuQYe9vIijtntVH6EsHmWc24', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3825.0987013433414!2d107.61347699999999!3d16.521114!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3141a10df33a083b%3A0x10306f98274eb769!2sKobi%20Onsen%20Resort%20Hue%2C%20Affiliated%20by%20Melia!5e0!3m2!1svi!2s!4v1764600401556!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(53, 1, 'Muong Thanh Holiday Hue Hotel', 'hotel', 'Huế', '1000000', 'Từ sự kiện doanh nghiệp đến họp mặt công ty, Muong Thanh Holiday Hue Hotel cung cấp đầy đủ các dịch vụ và tiện nghi đáp ứng mọi nhu cầu của quý khách và đồng nghiệp.\n\nDù quý khách muốn tổ chức một sự kiện hay các dịp kỷ niệm đặc biệt khác, Muong Thanh Holiday Hue Hotel là lựa chọn tuyệt vời cho quý khách với phòng chức năng rộng lớn, được trang bị đầy đủ để sẵn sàng đáp ứng mọi yêu cầu.\n\nKhách sạn này là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn hay tuần trăng mật của các cặp đôi. Quý khách hãy tận hưởng những đêm đáng nhớ nhất cùng người thương của mình tại Muong Thanh Holiday Hue Hotel.\n\nMuong Thanh Holiday Hue Hotel là lựa chọn sáng giá dành cho những ai đang tìm kiếm một trải nghiệm xa hoa đầy thú vị trong kỳ nghỉ của mình. Lưu trú tại đây cũng là cách để quý khách chiều chuộng bản thân với những dịch vụ xuất sắc nhất và khiến kỳ nghỉ của mình trở nên thật đáng nhớ.\n\nHãy sẵn sàng đón nhận trải nghiệm khó quên bằng dịch vụ độc đáo và hoàn hảo của khách sạn cùng các tiện nghi đầy đủ, đáp ứng mọi nhu cầu của quý khách.\n\nTrung tâm thể dục của khách sạn là một trong những tiện nghi không thể bỏ qua khi lưu trú tại đây.\n\nHưởng thụ một ngày thư thái đầy thú vị tại hồ bơi dù quý khách đang du lịch một mình hay cùng người thân.\n\nNhận ưu đãi đặc biệt dành cho các liệu pháp spa tinh tuý nhất giúp thư giãn tinh thần và làm tươi trẻ cơ thể.\n\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\n\nTận hưởng những món ăn yêu thích với phong cách ẩm thực đặc biệt từ Muong Thanh Holiday Hue Hotel chỉ dành riêng cho quý khách.\n\nSóng WiFi phủ khắp các khu vực chung của khách sạn cho phép quý khách luôn kết nối với gia đình và bè bạn.\n\nMuong Thanh Holiday Hue Hotel là khách sạn sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\n\nTận hưởng trải nghiệm lưu trú xa hoa đầy thú vị không đâu sánh bằng tại Muong Thanh Holiday Hue Hotel.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuDrvgMY2AVYnyzdxJ39yFL_WbpvtD1wm0CaNoF8o7h3Il4noOJCeeVcPI7wi5PRMfL1btdG8pqW25RGjR-SonElWR2VukmexroNqQagpynpDmh6PqZEfU9CD1Qaav3NM3O0xgXzec-bjdBA5VR9A523HSotNrPoV3f6tPvChAYEHYQn_da2dQJjOs8d-GLGh5vh9vIiVmivt', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3826.1212346610696!2d107.5934473!3d16.4693978!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3141a13cb6ac8431%3A0x4b9904d7eb09b194!2zS2jDoWNoIFPhuqFuIE3GsOG7nW5nIFRoYW5oIEhvbGlkYXkgSHXhur8!5e0!3m2!1svi!2s!4v1764600583652!5m2!1svi!2s', 0, '2026-03-08 18:49:23'),
(54, 4, 'Kly Luxury Hotel', 'hotel', 'Huế', '500000', 'Dành cho những du khách muốn du lịch thoải mái cùng ngân sách tiết kiệm, Kly Luxury Hotel sẽ là lựa chọn lưu trú hoàn hảo, nơi cung cấp các tiện nghi chất lượng và dịch vụ tuyệt vời.\n\nHãy tận hưởng thời gian vui vẻ cùng cả gia đình với hàng loạt tiện nghi giải trí tại Kly Luxury Hotel , một khách sạn tuyệt vời phù hợp cho mọi kỳ nghỉ bên người thân.\n\nKly Luxury Hotel là lựa chọn sáng giá dành cho những ai đang tìm kiếm một trải nghiệm xa hoa đầy thú vị trong kỳ nghỉ của mình. Lưu trú tại đây cũng là cách để quý khách chiều chuộng bản thân với những dịch vụ xuất sắc nhất và khiến kỳ nghỉ của mình trở nên thật đáng nhớ.\n\nDu lịch một mình cũng không hề kém phần thú vị và Kly Luxury Hotel là nơi thích hợp dành riêng cho những ai đề cao sự riêng tư trong kỳ lưu trú.\n\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\n\nSóng WiFi phủ khắp các khu vực chung của khách sạn cho phép quý khách luôn kết nối với gia đình và bè bạn.\n\nKly Luxury Hotel là khách sạn sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\n\nKly Luxury Hotel là lựa chọn lý tưởng cho những ai đang tìm kiếm một phòng nghỉ thoải mái với giá thành hợp lý.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuDrvgMY2AVYnyzdxJ39yFL_WbpvtD1wm0CaNoF8o7h3Il4noOJCeeVcPI7wi5PRMfL1btdG8pqW25RGjR-SonElWR2VukmexroNqQagpynpDmh6PqZEfU9CD1Qaav3NM3O0xgXzec-bjdBA5VR9A523HSotNrPoV3f6tPvChAYEHYQn_da2dQJjOs8d-GLGh5vh9vIiVmivt', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3826.214104750274!2d107.59013727471914!3d16.464692928730518!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3141a186361d9b9b%3A0xb067aa238fb07ee9!2sKLY%20LUXURY%20HOTEL%20HUE!5e0!3m2!1svi!2s!4v1764600835638!5m2!1svi!2s', 0, '2026-03-08 18:49:23'),
(55, 1, 'Moonlight Hotel Hue', 'hotel', 'Huế', '600000', 'Không chỉ sở hữu vị trí giúp quý khách dễ dàng ghé thăm những địa điểm lý thú trong chuyến hành trình, Moonlight Hotel Hue cũng sẽ mang đến cho quý khách trải nghiệm lưu trú mỹ mãn.\n\nMoonlight Hotel Hue là đề xuất hàng đầu dành cho những tín đồ du lịch "bụi" mong muốn được nghỉ tại một khách sạn vừa thoải mái lại hợp túi tiền.\n\nKhi lưu trú tại khách sạn thì nội thất và kiến trúc hẳn là hai yếu tố quan trọng khiến quý khách mãn nhãn. Với thiết kế độc đáo, Moonlight Hotel Hue mang đến không gian lưu trú làm hài lòng quý khách.\n\nDành cho những du khách muốn du lịch thoải mái cùng ngân sách tiết kiệm, Moonlight Hotel Hue sẽ là lựa chọn lưu trú hoàn hảo, nơi cung cấp các tiện nghi chất lượng và dịch vụ tuyệt vời.\n\nTừ sự kiện doanh nghiệp đến họp mặt công ty, Moonlight Hotel Hue cung cấp đầy đủ các dịch vụ và tiện nghi đáp ứng mọi nhu cầu của quý khách và đồng nghiệp.\n\nDù quý khách muốn tổ chức một sự kiện hay các dịp kỷ niệm đặc biệt khác, Moonlight Hotel Hue là lựa chọn tuyệt vời cho quý khách với phòng chức năng rộng lớn, được trang bị đầy đủ để sẵn sàng đáp ứng mọi yêu cầu.\n\nHãy tận hưởng thời gian vui vẻ cùng cả gia đình với hàng loạt tiện nghi giải trí tại Moonlight Hotel Hue, một khách sạn tuyệt vời phù hợp cho mọi kỳ nghỉ bên người thân.\n\nKhách sạn này là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn hay tuần trăng mật của các cặp đôi. Quý khách hãy tận hưởng những đêm đáng nhớ nhất cùng người thương của mình tại Moonlight Hotel Hue.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuDrvgMY2AVYnyzdxJ39yFL_WbpvtD1wm0CaNoF8o7h3Il4noOJCeeVcPI7wi5PRMfL1btdG8pqW25RGjR-SonElWR2VukmexroNqQagpynpDmh6PqZEfU9CD1Qaav3NM3O0xgXzec-bjdBA5VR9A523HSotNrPoV3f6tPvChAYEHYQn_da2dQJjOs8d-GLGh5vh9vIiVmivt', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3826.1218446845064!2d107.5942676!3d16.469366900000004!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3141a13cd1fb6a3d%3A0xb69ec59e61660f7a!2sMoonlight%20Hotel%20Hue!5e0!3m2!1svi!2s!4v1764600925247!5m2!1svi!2s', 0, '2026-03-08 18:49:23'),
(101, 1, 'Goldient Boutique Hotel', 'hotel', 'Huế', '0', 'Không chỉ sở hữu vị trí giúp quý khách dễ dàng ghé thăm những địa điểm lý thú trong chuyến hành trình, Goldient Boutique Hotel cũng sẽ mang đến cho quý khách trải nghiệm lưu trú mỹ mãn.\n\nTọa lạc gần sân bay, Goldient Boutique Hotel là nơi nghỉ ngơi lý tưởng trong lúc quý khách đang chờ chuyến bay kế tiếp. Quý khách có thể tận hưởng không gian nghỉ dưỡng vừa ý nơi đây trong quá trình quá cảnh.\n\nKhi lưu trú tại khách sạn thì nội thất và kiến trúc hẳn là hai yếu tố quan trọng khiến quý khách mãn nhãn. Với thiết kế độc đáo, Goldient Boutique Hotel mang đến không gian lưu trú làm hài lòng quý khách.\n\nTừ sự kiện doanh nghiệp đến họp mặt công ty, Goldient Boutique Hotel cung cấp đầy đủ các dịch vụ và tiện nghi đáp ứng mọi nhu cầu của quý khách và đồng nghiệp.\n\nDù quý khách muốn tổ chức một sự kiện hay các dịp kỷ niệm đặc biệt khác, Goldient Boutique Hotel là lựa chọn tuyệt vời cho quý khách với phòng chức năng rộng lớn, được trang bị đầy đủ để sẵn sàng đáp ứng mọi yêu cầu.\n\nHãy tận hưởng thời gian vui vẻ cùng cả gia đình với hàng loạt tiện nghi giải trí tại Goldient Boutique Hotel, một khách sạn tuyệt vời phù hợp cho mọi kỳ nghỉ bên người thân.\n\nKhách sạn này là lựa chọn lý tưởng cho cả du khách chơi golf nghiệp dư lẫn chuyên nghiệp.\n\nHãy tận hưởng trải nghiệm lưu trú có một không hai tại toà nhà mang đậm dấu ấn lịch sử của Goldient Boutique Hotel, điều quý khách khó có thể tìm thấy tại bất kỳ đâu.\n\nKhách sạn này là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn hay tuần trăng mật của các cặp đôi. Quý khách hãy tận hưởng những đêm đáng nhớ nhất cùng người thương của mình tại Goldient Boutique Hotel\n\nNếu dự định có một kỳ nghỉ dài, thì Goldient Boutique Hotel chính là lựa chọn dành cho quý khách. Với đầy đủ tiện nghi với chất lượng dịch vụ tuyệt vời, Goldient Boutique Hotel sẽ khiến quý khách cảm thấy thoải mái như đang ở nhà vậy.\n\nGoldient Boutique Hotel là lựa chọn sáng giá dành cho những ai đang tìm kiếm một trải nghiệm xa hoa đầy thú vị trong kỳ nghỉ của mình. Lưu trú tại đây cũng là cách để quý khách chiều chuộng bản thân với những dịch vụ xuất sắc nhất và khiến kỳ nghỉ của mình trở nên thật đáng nhớ.\n\nBạn có phải là tín đồ mua sắm? Lưu trú tại Goldient Boutique Hotel chắc chắn sẽ thoả mãn bạn với hàng loạt các trung tâm mua sắm kề cận.\n\nDu lịch một mình cũng không hề kém phần thú vị và Goldient Boutique Hotel là nơi thích hợp dành riêng cho những ai đề cao sự riêng tư trong kỳ lưu trú.\n\nHãy sẵn sàng đón nhận trải nghiệm khó quên bằng dịch vụ độc đáo và hoàn hảo của khách sạn cùng các tiện nghi đầy đủ, đáp ứng mọi nhu cầu của quý khách.\n\nHưởng thụ một ngày thư thái đầy thú vị tại hồ bơi dù quý khách đang du lịch một mình hay cùng người thân.\n\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\n\nTận hưởng những món ăn yêu thích với phong cách ẩm thực đặc biệt từ Goldient Boutique Hotel chỉ dành riêng cho quý khách.\n\nSóng WiFi phủ khắp các khu vực chung của khách sạn cho phép quý khách luôn kết nối với gia đình và bè bạn.\n\nGoldient Boutique Hotel là khách sạn sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\n\nTận hưởng trải nghiệm lưu trú xa hoa đầy thú vị không đâu sánh bằng tại Goldient Boutique Hotel.', 'https://lh3.googleusercontent.com/aida-public/AB6AXuDrvgMY2AVYnyzdxJ39yFL_WbpvtD1wm0CaNoF8o7h3Il4noOJCeeVcPI7wi5PRMfL1btdG8pqW25RGjR-SonElWR2VukmexroNqQagpynpDmh6PqZEfU9CD1Qaav3NM3O0xgXzec-bjdBA5VR9A523HSotNrPoV3f6tPvChAYEHYQn_da2dQJjOs8d-GLGh5vh9vIiVmivt', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3903.6646599249693!2d108.4457707!3d11.928409499999999!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3171137eddaf9c99%3A0x2b2768f9f5a7920d!2sGoldient%20Boutique%20Hotel%20(C%C3%B4ng%20Ty%20TNHH%20XD%20Tu%E1%BA%A5n%20Gia%20Ph%C3%A1t)!5e0!3m2!1svi!2s!4v1764610267373!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(102, 1, 'Khách sạn MerPerle Dalat', 'hotel', 'Đà Lạt, Lâm Đồng', '1800000', 'Khách sạn MerPerle Đà Lạt là một khách sạn gần Sân bay, một nơi ở lý tưởng trong khi chờ chuyến bay tiếp theo của bạn. Tận hưởng một nơi nghỉ ngơi thoải mái trong quá trình di chuyển của bạn.\n\nKhách sạn MerPerle Đà Lạt rất được khuyến khích cho những người đi ba lô, những người muốn có một kỳ nghỉ giá cả phải chăng nhưng đồng thời vẫn thoải mái.\n\nTừ sự kiện kinh doanh đến các cuộc họp công ty, Khách sạn MerPerle Đà Lạt cung cấp các dịch vụ và tiện nghi đầy đủ mà bạn và đồng nghiệp của bạn cần.\n\nCho dù bạn đang lên kế hoạch cho một sự kiện hay những dịp đặc biệt khác, Khách sạn MerPerle Đà Lạt là một lựa chọn tuyệt vời cho bạn với một phòng chức năng lớn và được trang bị tốt để phù hợp với yêu cầu của bạn.\n\nHãy vui vẻ với nhiều tiện nghi giải trí khác nhau dành cho bạn và cả gia đình tại Khách sạn MerPerle Đà Lạt, một nơi ở tuyệt vời cho kỳ nghỉ của gia đình bạn.\n\nTrải nghiệm một kỳ nghỉ độc đáo tại tòa nhà lịch sử của Khách sạn MerPerle Đà Lạt, điều mà bạn hiếm khi tìm thấy ở những nơi khác.\n\nKhách sạn này là sự lựa chọn hoàn hảo cho các cặp đôi đang tìm kiếm một kỳ nghỉ lãng mạn hoặc một nơi nghỉ dưỡng trăng mật. Tận hưởng những đêm đáng nhớ nhất với người thân yêu của bạn bằng cách ở tại Khách sạn MerPerle Đà Lạt.\n\nNếu bạn dự định có một kỳ nghỉ dài hạn, việc ở tại Khách sạn MerPerle Đà Lạt là lựa chọn phù hợp với bạn. Cung cấp nhiều tiện nghi và chất lượng dịch vụ tuyệt vời, chỗ ở này chắc chắn sẽ khiến bạn cảm thấy như ở nhà.\n\nKhách sạn MerPerle Đà Lạt là sự lựa chọn tuyệt vời cho những ai đang tìm kiếm một kỳ nghỉ sang trọng. Hãy nuông chiều bản thân với những dịch vụ tuyệt vời nhất và làm cho kỳ nghỉ của bạn đáng nhớ bằng cách ở lại đây.\n\nBạn là một người nghiện mua sắm? Ở tại Khách sạn MerPerle Đà Lạt chắc chắn sẽ làm bạn thích thú với vô số trung tâm mua sắm gần đó.\n\nTrong khi đi du lịch với bạn bè có thể rất vui, thì việc đi du lịch một mình lại có những đặc quyền riêng. Đối với chỗ ở, Khách sạn MerPerle Đà Lạt phù hợp với những người coi trọng sự riêng tư trong thời gian lưu trú của bạn.\n\nLiệu pháp spa là một trong những tính năng chính của khách sạn. Hãy nuông chiều bản thân bằng liệu pháp thư giãn giúp bạn trẻ hóa.\n\nDịch vụ chất lượng cao nhất cùng với các tiện nghi phong phú sẽ giúp bạn có được trải nghiệm kỳ nghỉ tuyệt vời nhất.\n\nTrung tâm thể dục của khách sạn là một điều bạn phải thử trong thời gian bạn ở đây.\n\nCó một ngày vui vẻ và thư giãn tại hồ bơi, cho dù bạn đi du lịch một mình hay với những người thân yêu của bạn.\n\nNhận ưu đãi tốt nhất cho chất lượng tốt nhất của liệu pháp spa để thư giãn và trẻ hóa bản thân.\n\nQuầy lễ tân 24 giờ luôn sẵn sàng phục vụ bạn, từ nhận phòng đến trả phòng hoặc bất kỳ sự hỗ trợ nào bạn cần. Nếu bạn muốn nhiều hơn, đừng ngần ngại hỏi quầy lễ tân, chúng tôi luôn sẵn sàng phục vụ bạn.\n\nThưởng thức các món ăn yêu thích của bạn với các món ăn đặc biệt từ Khách sạn MerPerle Đà Lạt dành riêng cho bạn.\n\nWi-Fi có sẵn trong các khu vực công cộng của khách sạn để giúp bạn kết nối với gia đình và bạn bè.\n\nKhách sạn MerPerle Đà Lạt là một khách sạn có sự thoải mái tuyệt vời và dịch vụ tuyệt vời theo hầu hết khách của khách sạn.\n\nTận hưởng những món ăn sang trọng và trải nghiệm vô song bằng cách ở tại Khách sạn MerPerle Đà Lạt.', 'http://googleusercontent.com/profile/picture/41', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3903.481647297428!2d108.4583036!3d11.9411183!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3171132bd1dd7c6f%3A0x28989de80f2b7731!2sMerPerle%20Dalat%20Hotel!5e0!3m2!1svi!2s!4v1764610540444!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(103, 1, 'Leaf Beachfront Hotel Da Nang', 'hotel', 'Đà Nẵng', '950000', 'Dành cho những du khách muốn du lịch thoải mái cùng ngân sách tiết kiệm, Leaf Beachfront Hotel Da Nang sẽ là lựa chọn lưu trú hoàn hảo, nơi cung cấp các tiện nghi chất lượng và dịch vụ tuyệt vời.\n\nKhách sạn này là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn hay tuần trăng mật của các cặp đôi. Quý khách hãy tận hưởng những đêm đáng nhớ nhất cùng người thương của mình tại Leaf Beachfront Hotel Da Nang\n\nLeaf Beachfront Hotel Da Nang là lựa chọn sáng giá dành cho những ai đang tìm kiếm một trải nghiệm xa hoa đầy thú vị trong kỳ nghỉ của mình. Lưu trú tại đây cũng là cách để quý khách chiều chuộng bản thân với những dịch vụ xuất sắc nhất và khiến kỳ nghỉ của mình trở nên thật đáng nhớ.\n\nKhi lưu trú tại khách sạn thì nội thất và kiến trúc hẳn là hai yếu tố quan trọng khiến quý khách mãn nhãn. Với thiết kế độc đáo, Leaf Beachfront Hotel Da Nang mang đến không gian lưu trú làm hài lòng quý khách.\n\nHãy tận hưởng thời gian vui vẻ cùng cả gia đình với hàng loạt tiện nghi giải trí tại Leaf Beachfront Hotel Da Nang, một khách sạn tuyệt vời phù hợp cho mọi kỳ nghỉ bên người thân.\n\nNếu dự định có một kỳ nghỉ dài, thì Leaf Beachfront Hotel Da Nang chính là lựa chọn dành cho quý khách. Với đầy đủ tiện nghi với chất lượng dịch vụ tuyệt vời, Leaf Beachfront Hotel Da Nang sẽ khiến quý khách cảm thấy thoải mái như đang ở nhà vậy.\n\nHưởng thụ một ngày thư thái đầy thú vị tại hồ bơi dù quý khách đang du lịch một mình hay cùng người thân.\n\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\n\nTận hưởng những món ăn yêu thích với phong cách ẩm thực đặc biệt từ Leaf Beachfront Hotel Da Nang chỉ dành riêng cho quý khách.\n\nLeaf Beachfront Hotel Da Nang là khách sạn sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\n\nVới những tiện nghi sẵn có Leaf Beachfront Hotel Da Nang thực sự là một nơi lưu trú hoàn hảo.', 'http://googleusercontent.com/profile/picture/43', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3833.607479140029!2d108.24813879999999!3d16.0858461!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3142173a22bf7925%3A0x1fa7d67836459fa8!2sLeaf%20Hotel!5e0!3m2!1svi!2s!4v1764610795410!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(104, 1, 'G8 Luxury Hotel And Spa Da Nang', 'hotel', 'Đà Nẵng', '700000', 'Khách sạn này là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn hay tuần trăng mật của các cặp đôi. Quý khách hãy tận hưởng những đêm đáng nhớ nhất cùng người thương của mình tại G8 Luxury Hotel And Spa Da Nang\n\nG8 Luxury Hotel And Spa Da Nang là lựa chọn sáng giá dành cho những ai đang tìm kiếm một trải nghiệm xa hoa đầy thú vị trong kỳ nghỉ của mình. Lưu trú tại đây cũng là cách để quý khách chiều chuộng bản thân với những dịch vụ xuất sắc nhất và khiến kỳ nghỉ của mình trở nên thật đáng nhớ.\n\nBạn có phải là tín đồ mua sắm? Lưu trú tại G8 Luxury Hotel And Spa Da Nang chắc chắn sẽ thoả mãn bạn với hàng loạt các trung tâm mua sắm kề cận.\n\nKhi lưu trú tại khách sạn thì nội thất và kiến trúc hẳn là hai yếu tố quan trọng khiến quý khách mãn nhãn. Với thiết kế độc đáo, G8 Luxury Hotel And Spa Da Nang mang đến không gian lưu trú làm hài lòng quý khách.\n\nTừ sự kiện doanh nghiệp đến họp mặt công ty, G8 Luxury Hotel And Spa Da Nang cung cấp đầy đủ các dịch vụ và tiện nghi đáp ứng mọi nhu cầu của quý khách và đồng nghiệp.\n\nHãy tận hưởng thời gian vui vẻ cùng cả gia đình với hàng loạt tiện nghi giải trí tại G8 Luxury Hotel And Spa Da Nang, một khách sạn tuyệt vời phù hợp cho mọi kỳ nghỉ bên người thân.\n\nNếu dự định có một kỳ nghỉ dài, thì G8 Luxury Hotel And Spa Da Nang chính là lựa chọn dành cho quý khách. Với đầy đủ tiện nghi với chất lượng dịch vụ tuyệt vời, G8 Luxury Hotel And Spa Da Nang sẽ khiến quý khách cảm thấy thoải mái như đang ở nhà vậy.\n\nHãy sẵn sàng đón nhận trải nghiệm khó quên bằng dịch vụ độc đáo và hoàn hảo của khách sạn cùng các tiện nghi đầy đủ, đáp ứng mọi nhu cầu của quý khách.\n\nHưởng thụ một ngày thư thái đầy thú vị tại hồ bơi dù quý khách đang du lịch một mình hay cùng người thân.\n\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\n\nSóng WiFi phủ khắp các khu vực chung của khách sạn cho phép quý khách luôn kết nối với gia đình và bè bạn.\n\nG8 Luxury Hotel And Spa Da Nang là khách sạn sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\n\nTận hưởng trải nghiệm lưu trú xa hoa đầy thú vị không đâu sánh bằng tại G8 Luxury Hotel And Spa Da Nang.', 'http://googleusercontent.com/profile/picture/44', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3833.897091574162!2d108.21707819999999!3d16.0708291!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x31421828f96d9b7b%3A0xb47c13a96e71ee54!2zS2jDoWNoIHPhuqFuIEc4IEx1eHVyeQ!5e0!3m2!1svi!2s!4v1764611132012!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(105, 1, 'DeLaSol Sapa Hotel', 'hotel', 'Sapa, Lào Cai', '900000', 'Khi lưu trú tại khách sạn thì nội thất và kiến trúc hẳn là hai yếu tố quan trọng khiến quý khách mãn nhãn. Với thiết kế độc đáo, DeLaSol Sapa Hotel mang đến không gian lưu trú làm hài lòng quý khách.\n\nTừ sự kiện doanh nghiệp đến họp mặt công ty, DeLaSol Sapa Hotel cung cấp đầy đủ các dịch vụ và tiện nghi đáp ứng mọi nhu cầu của quý khách và đồng nghiệp.\n\nDù quý khách muốn tổ chức một sự kiện hay các dịp kỷ niệm đặc biệt khác, DeLaSol Sapa Hotel là lựa chọn tuyệt vời cho quý khách với phòng chức năng rộng lớn, được trang bị đầy đủ để sẵn sàng đáp ứng mọi yêu cầu.\n\nHãy tận hưởng thời gian vui vẻ cùng cả gia đình với hàng loạt tiện nghi giải trí tại DeLaSol Sapa Hotel , một khách sạn tuyệt vời phù hợp cho mọi kỳ nghỉ bên người thân.\n\nKhách sạn này là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn hay tuần trăng mật của các cặp đôi. Quý khách hãy tận hưởng những đêm đáng nhớ nhất cùng người thương của mình tại DeLaSol Sapa Hotel\n\nNếu dự định có một kỳ nghỉ dài, thì DeLaSol Sapa Hotel chính là lựa chọn dành cho quý khách. Với đầy đủ tiện nghi với chất lượng dịch vụ tuyệt vời, DeLaSol Sapa Hotel sẽ khiến quý khách cảm thấy thoải mái như đang ở nhà vậy.\n\nDeLaSol Sapa Hotel là lựa chọn sáng giá dành cho những ai đang tìm kiếm một trải nghiệm xa hoa đầy thú vị trong kỳ nghỉ của mình. Lưu trú tại đây cũng là cách để quý khách chiều chuộng bản thân với những dịch vụ xuất sắc nhất và khiến kỳ nghỉ của mình trở nên thật đáng nhớ.\n\nDu lịch một mình cũng không hề kém phần thú vị và DeLaSol Sapa Hotel là nơi thích hợp dành riêng cho những ai đề cao sự riêng tư trong kỳ lưu trú.\n\nHãy sẵn sàng đón nhận trải nghiệm khó quên bằng dịch vụ độc đáo và hoàn hảo của khách sạn cùng các tiện nghi đầy đủ, đáp ứng mọi nhu cầu của quý khách.\n\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Nếu cần giúp đỡ xin hãy liên hệ đội ngũ tiếp tân, chúng tôi luôn sẵn sàng hỗ trợ quý khách.\n\nTận hưởng những món ăn yêu thích với phong cách ẩm thực đặc biệt từ DeLaSol Sapa Hotel chỉ dành riêng cho quý khách.\n\nSóng WiFi phủ khắp các khu vực chung của khách sạn cho phép quý khách luôn kết nối với gia đình và bè bạn.\n\nDeLaSol Sapa Hotel là khách sạn sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc theo nhận định của hầu hết khách lưu trú.\n\nTận hưởng trải nghiệm lưu trú xa hoa đầy thú vị không đâu sánh bằng tại DeLaSol Sapa Hotel .', 'http://googleusercontent.com/profile/picture/45', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3690.5629750357675!2d103.8435226!3d22.332362!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x36cd412db7a972dd%3A0x3c78e67b20dfeb8c!2sDeLaSol%20Sapa%20Hotel%20-%20Central%20Boutique%20Hotel!5e0!3m2!1svi!2s!4v1764611496116!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(106, 1, 'Sapa Jade Hill Resort And Spa', 'resort', 'Sapa, Lào Cai', '1700000', 'Sở hữu vị trí thuận lợi ngay thung lũng Mường Hoa, từ Sapa Jade Hill Resort And Spa, du khách có thể dễ dàng đến các địa điểm du lịch nổi tiếng tại trung tâm thị trấn trong khoảng cách chỉ 2-3 km như Nhà thờ Đá, cáp treo Fansipan, bản Cát Cát và Tả Van, chợ Sapa…\n\nSapa Jade Hill Resort And Spa là mô hình biệt thự và bungalow nghỉ dưỡng, bao quanh bởi rừng nguyên sinh, thung lũng hoa và núi non trập trùng, mang đến những giây phút nghỉ ngơi, tận hưởng thiên nhiên trong lành ngay trung tâm phố núi. Lựa chọn nghỉ ngơi tại đây, du khách sẽ được trải nghiệm cảm giác thức dậy giữa khung cảnh thung lũng xanh trải dài ngút mắt, hướng mắt ra các thửa ruộng bậc thang uốn lượn, tận hưởng cảm giác mây và sương sà ngang tầm mắt.\n\nSapa Jade Hill Resort And Spa có hai dạng phòng chủ đạo là bungalow và villa.\n\nBungalow được thiết kế hoàn toàn bằng gỗ thông và cọ, vừa truyền thống, ấm áp, lại vẫn mang vẻ sang trọng của một khách sạn nghỉ dưỡng hàng đầu.\n\nBiệt thự mang mang phong cách chủ đạo kiểu Âu với ống khói và lò sưởi, kết hợp với hình ảnh nhà sàn đặc trưng của đồng bào dân tộc thiểu số vùng Tây Bắc. Trong các biệt thự còn có cả khu vực nhà bếp và lò sưởi. Đừng bỏ qua cơ hội tự tay nhóm bếp và nướng khoai ngay tại khung lò sưởi, thưởng thức củ khoai ấm nóng giản dị, những lại gợi về những kí ức khó quên.\n\nThiết kế nội thất tại Sapa Jade Hill Resort And Spa được chăm chút đến từng chi tiết, mang phong cách trang nhã, tinh tế. Các vật dụng được tô điểm với các họa tiết thổ cẩm, chất liệu mộc mạc, tô đậm nét văn hóa truyền thống địa phương.\n\nSapa Jade Hill Resort And Spa còn có nhà hàng Đồi Ngọc, phục vụ các món ăn mang hương vị ẩm thực dân dã vùng Tây Bắc và ẩm thực châu Âu tinh tế. Các món ăn được chế biến từ chính tay bếp trưởng người Pháp, kết hợp với những nguyên liệu tươi ngon nhất cũng vùng núi cao như cá hồi, rau củ, gà, lợn bản… mang đến trải nghiệm ẩm thực trọn vẹn và đa dạng nhất cho du khách.\n\nKhách sạn còn có hồ bơi, cùng hệ thống spa chuyên nghiệp nhất, là sự lựa chọn nghỉ ngơi tuyệt vời cho du khách sau một ngày tham quan mệt mỏi.', 'http://googleusercontent.com/profile/picture/46', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3690.7944251927624!2d103.8546327!3d22.323613200000004!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x36cd41235c963d7b%3A0xc41c3c35fdf8edc8!2zUmVzb3J0IG5naOG7iSBkxrDhu6FuZyAtIFNhcGEgSmFkZSBIaWxs!5e0!3m2!1svi!2s!4v1764611724363!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(107, 1, 'Comodo Nha Trang Hotel', 'hotel', 'Nha Trang, Khánh Hòa', '1050000', 'Tọa lạc tại vị trí đắc địa trên con đường vàng Trần Phú, Comodo Nha Trang Hotel là điểm dừng chân lý tưởng để quý khách tận hưởng trọn vẹn vẻ đẹp của vịnh biển Nha Trang.\n\nSở hữu lối kiến trúc hiện đại và tinh tế, Comodo Nha Trang Hotel mang đến không gian nghỉ dưỡng sang trọng, đẳng cấp, đảm bảo sự thoải mái tuyệt đối cho quý khách dù là chuyến đi công tác hay nghỉ dưỡng.\n\nKhách sạn này là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn. Quý khách hãy tận hưởng những đêm đáng nhớ nhất cùng người thương của mình trong không gian ấm cúng và tiện nghi tại Comodo Nha Trang Hotel.\n\nMột trong những điểm nhấn của khách sạn là hồ bơi vô cực trên tầng cao, nơi quý khách có thể đắm mình trong làn nước mát lạnh và ngắm nhìn toàn cảnh thành phố biển xinh đẹp.\n\nTừ sự kiện doanh nghiệp đến họp mặt công ty, Comodo Nha Trang Hotel cung cấp đầy đủ các dịch vụ và tiện nghi đáp ứng mọi nhu cầu của quý khách và đồng nghiệp với hệ thống phòng hội nghị trang bị hiện đại.\n\nNếu dự định có một kỳ nghỉ dài, thì Comodo Nha Trang Hotel chính là lựa chọn dành cho quý khách. Với đầy đủ tiện nghi cùng chất lượng dịch vụ tuyệt vời, nơi đây sẽ khiến quý khách cảm thấy thoải mái như đang ở nhà.\n\nQuầy tiếp tân 24 giờ luôn sẵn sàng phục vụ quý khách từ thủ tục nhận phòng đến trả phòng hay bất kỳ yêu cầu nào. Đội ngũ nhân viên chuyên nghiệp và thân thiện luôn sẵn sàng hỗ trợ để kỳ nghỉ của quý khách trở nên hoàn hảo.\n\nTận hưởng những món ăn yêu thích với phong cách ẩm thực đa dạng tại nhà hàng của khách sạn, từ các món đặc sản địa phương đến ẩm thực quốc tế.\n\nVới vị trí thuận lợi, từ khách sạn quý khách có thể dễ dàng tiếp cận các điểm tham quan nổi tiếng, trung tâm mua sắm và khu vui chơi giải trí sầm uất của Nha Trang.\n\nComodo Nha Trang Hotel là khách sạn sở hữu đầy đủ tiện nghi và dịch vụ xuất sắc, hứa hẹn mang đến cho quý khách trải nghiệm lưu trú khó quên.', 'http://googleusercontent.com/profile/picture/47', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3899.255885181542!2d109.1980756!3d12.2309457!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x317067de00952ab5%3A0x3a2caca4f28a4c62!2sComodo%20Nha%20Trang%20Hotel!5e0!3m2!1svi!2s!4v1764612161415!5m2!1svi!2s', 1, '2026-03-08 18:49:23'),
(108, 1, 'Muong Thanh Luxury Nha Trang Hotel', 'hotel', 'Nha Trang, Khánh Hòa', '1250000', 'Tọa lạc tại vị trí đắc địa số 60 Trần Phú, Muong Thanh Luxury Nha Trang Hotel nổi bật với chiều cao ấn tượng và tầm nhìn toàn cảnh ra vịnh Nha Trang xinh đẹp. Đây là điểm dừng chân lý tưởng cho du khách muốn trải nghiệm kỳ nghỉ dưỡng sang trọng ngay trung tâm phố biển.\n\nKhách sạn cung cấp hệ thống phòng nghỉ hiện đại, tiện nghi với không gian ấm cúng, trang nhã. Từ ban công phòng nghỉ, quý khách có thể đón bình minh trên biển hoặc ngắm nhìn thành phố lung linh về đêm.\n\nMuong Thanh Luxury Nha Trang Hotel là lựa chọn hoàn hảo cho các kỳ nghỉ mát lãng mạn hay tuần trăng mật. Hãy tận hưởng những giây phút ngọt ngào bên người thương trong không gian riêng tư và đẳng cấp.\n\nĐối với khách doanh nhân, khách sạn cung cấp các phòng hội nghị, hội thảo với trang thiết bị âm thanh, ánh sáng hiện đại, đáp ứng mọi nhu cầu tổ chức sự kiện chuyên nghiệp.\n\nHệ thống nhà hàng của khách sạn phục vụ đa dạng các món ăn từ đặc sản địa phương đậm đà hương vị biển đến các món Á - Âu tinh tế, được chế biến bởi đội ngũ đầu bếp tài hoa.\n\nSau một ngày dài khám phá, quý khách có thể thư giãn tại hồ bơi ngoài trời, tái tạo năng lượng với các liệu pháp massage tại spa hoặc rèn luyện sức khỏe tại phòng gym hiện đại.\n\nQuầy lễ tân 24 giờ luôn sẵn sàng hỗ trợ quý khách với sự chuyên nghiệp và thân thiện, đảm bảo mọi nhu cầu của quý khách đều được đáp ứng nhanh chóng.\n\nVới vị trí thuận lợi, dịch vụ đẳng cấp và tiện nghi đầy đủ, Muong Thanh Luxury Nha Trang Hotel hứa hẹn mang đến cho quý khách một kỳ nghỉ trọn vẹn và đáng nhớ tại thành phố biển Nha Trang.', 'http://googleusercontent.com/profile/picture/48', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3899.1731199514365!2d109.1964462!3d12.236554700000001!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3170677ae037716b%3A0x34f80a4db849a372!2sM%C6%B0%E1%BB%9Dng%20Thanh%20Luxury%20Nha%20Trang!5e0!3m2!1svi!2s!4v1764612377046!5m2!1svi!2s', 1, '2026-03-08 18:49:23');
